local xml = require("xml")

function handle_request(ngx)
  local request_body = ngx.req.get_body_data()
  local xml_doc = xml.parse(request_body)
  local data = {}

  for _, node in ipairs(xml_doc:children()) do
    if node:name() == "entity" then
      data["entity"] = node:text()
    end
  end

  return data
end